4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    const result = nextGeneration([]);
7	    expect(result).toEqual([]);
8	  });
9	  it("should kill a single cell with no neighbors (underpopulation)", () => {
10	    const result = nextGeneration([[0, 0]]);
11	    expect(result).toEqual([]);
12	  });
13	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
14	    const result = nextGeneration([[0, 1], [1, 1]]);
15	    expect(result).toEqual([]);
16	  });
17	  it("should keep alive a cell with exactly 2 neighbors (survival)", () => {
18	    // L-shape: (0,0) has 2 neighbors: (1,0) and (0,1) -> survives
19	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
20	    expect(result).toContainEqual([0, 0]);
21	  });
22	  it("should keep alive a cell with exactly 3 neighbors (survival)", () => {
23	    // Cell (1,1) has 3 neighbors: (1,0), (0,1), (2,1) -> survives
24	    const result = nextGeneration([[1, 0], [0, 1], [1, 1], [2, 1]]);
25	    expect(result).toContainEqual([1, 1]);
26	  });
27	  it.todo("should kill a cell with 4 neighbors (overpopulation)");
28	  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)");
29	  it.todo("should keep a block pattern unchanged (still life)");
30	  it.todo("should oscillate a blinker pattern (oscillator)");
31	});
