1	const NEIGHBOR_OFFSETS: [number, number][] = [
2	  [-1, -1], [-1, 0], [-1, 1],
3	  [0, -1],           [0, 1],
4	  [1, -1],  [1, 0],  [1, 1],
5	];
6	
7	export function nextGeneration(liveCells: [number, number][]): [number, number][] {
8	  const isAlive = (x: number, y: number): boolean =>
9	    liveCells.some(([cx, cy]) => cx === x && cy === y);
10	
11	  const countNeighbors = (x: number, y: number): number =>
12	    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isAlive(x + dx, y + dy)).length;
13	
14	  return liveCells.filter(([x, y]) => {
15	    const count = countNeighbors(x, y);
16	    return count === 2 || count === 3;
17	  });
18	}
